function management_page_notices( $message = false ) {

		if ( isset( $_GET['message'] ) ) {
			switch ( (string) $_GET['message'] ) {
				case 'deleted' :
					$deleted = (int) $_GET['deleted'];
					if ( 1 == $deleted ) {
						$message = __( 'Poll deleted.', 'polldaddy' );
					} else {
						$message = sprintf(
							/* translators: %s is the number of polls deleted */
							_n( '%s Poll Deleted.', '%s Polls Deleted.', $deleted, 'polldaddy' ), number_format_i18n( $deleted ) );
					}
					break;
				case 'opened' :
					$opened = (int) $_GET['opened'];
					if ( 1 == $opened ) {
						$message = __( 'Poll opened.', 'polldaddy' );
					} else {
						$message = sprintf(
							/* translators: %s is the number of polls opened */
							_n( '%s Poll Opened.', '%s Polls Opened.', $opened, 'polldaddy' ), number_format_i18n( $opened ) );
					}
					break;
				case 'closed' :
					$closed = (int) $_GET['closed'];
					if ( 1 == $closed ) {
						$message = __( 'Poll closed.', 'polldaddy' );
					} else {
						$message = sprintf(
							/* translators: %s is the number of polls closed */
							_n( '%s Poll Closed.', '%s Polls Closed.', $closed, 'polldaddy' ), number_format_i18n( $closed ) );
					}
					break;
				case 'updated' :
					$message = __( 'Poll updated.', 'polldaddy' );
					break;
				case 'created' :
					$message = __( 'Poll created.', 'polldaddy' );
					if ( isset( $_GET['iframe'] ) ) {
						$message .= ' <input type="button" class="button polldaddy-send-to-editor" value="' . esc_attr( __( 'Embed in Post', 'polldaddy' ) ) . '" />';
					}
					break;
				case 'updated-style' :
					$message = __( 'Custom Style updated.', 'polldaddy' );
					break;
				case 'created-style' :
					$message = __( 'Custom Style created.', 'polldaddy' );
					break;
				case 'deleted-style' :
					$deleted = (int) $_GET['deleted'];
					if ( 1 == $deleted ) {
						$message = __( 'Custom Style deleted.', 'polldaddy' );
					} else {
						$message = sprintf(
							/* translators: %s is the number of styles deleted */
							_n( '%s Style Deleted.', '%s Custom Styles Deleted.', $deleted, 'polldaddy' ), number_format_i18n( $deleted ) );
					}
					break;
				case 'connected' :
				case 'imported-account' :
					$message = __( 'Account Linked.', 'polldaddy' );
					break;
				case 'api-key-not-added' :
					$message = __( 'There was a problem linking your account.', 'polldaddy' );
					break;
				case 'updated-options' :
					$message = __( 'Options Updated.', 'polldaddy' );
					break;
				case 'deleted-rating' :
					$deleted = (int) $_GET['deleted'];
					if ( 1 == $deleted ) {
						$message = __( 'Rating deleted.', 'polldaddy' );
					} else {
						$message = sprintf(
							/* translators: %s is the number of ratings deleted */
							_n( '%s Rating Deleted.', '%s Ratings Deleted.', $deleted, 'polldaddy' ), number_format_i18n( $deleted ) );
					}
					break;
			}//end switch
		}

		$is_POST = 'post' == strtolower( $_SERVER['REQUEST_METHOD'] );

		if ( $is_POST ) {
			switch ( $GLOBALS['action'] ) {
			case 'create-poll' :
				$message = __( 'Error: An error has occurred;  Poll not created.', 'polldaddy' );
				break;
			case 'edit-poll' :
				$message = __( 'Error: An error has occurred;  Poll not updated.', 'polldaddy' );
				break;
			case 'account' :
				if ( 'import' == $_POST['account'] )
					$message = __( 'Error: An error has occurred;  Account could not be imported.  Perhaps your email address or password is incorrect?', 'polldaddy' );
				else
					$message = __( 'Error: An error has occurred;  Account could not be created.', 'polldaddy' );
				break;
			}//end switch
		}

		if ( !$message )
			return;
		?>
		<div class='updated'><p><?php echo $message; ?></p></div>
		<?php
		$this->print_errors();
	}

/**
	 * Set snippet meta.
	 *
	 * @param int    $post_id   Post ID.
	 * @param string $type      Type to get keys for.
	 * @param array  $meta_keys Array of meta keys to save.
	 */
function set_postmeta( $post_id, $type, $meta_keys ) {
		$data = [];
		foreach ( $meta_keys as $snippet_key => $snippet_value ) {
			$value = get_post_meta( $post_id, '_bsf_' . $snippet_key, true );
			$this->validate_schema_data( $data, $value, $snippet_value );
		}

		if ( empty( $data ) ) {
			return;
		}

		// Convert post now.
		$data['@type']    = $this->validate_type( $type );
		$data['metadata'] = [
			'title'     => Helper::sanitize_schema_title( $data['@type'] ),
			'type'      => 'template',
			'isPrimary' => 1,
			'shortcode' => uniqid( 's-' ),
		];

		update_post_meta( $post_id, 'rank_math_schema_' . $data['@type'], $data );
	}

